package main

import (
	"bufio"
	"fmt"
	"log"
	"net"
	"strings"
	"sync"
	"time"
)

type Role string

const (
	RolePlayer Role = "player"
	RoleMod    Role = "mod"
	RoleAdmin  Role = "admin"
)

type Client struct {
	conn     net.Conn
	id       string
	name     string
	role     Role
	addr     string
	server   *Server
	sendMu   sync.Mutex
	closed   bool
	closeMu  sync.Mutex
	lastSeen time.Time
}

type Server struct {
	addr     string
	mu       sync.RWMutex
	clients  map[string]*Client
	banned   map[string]bool
	nextID   int
}

func NewServer(addr string) *Server {
	return &Server{
		addr:    addr,
		clients: make(map[string]*Client),
		banned:  make(map[string]bool),
	}
}

func (s *Server) Run() error {
	ln, err := net.Listen("tcp", s.addr)
	if err != nil {
		return err
	}
	log.Printf("server listening on %s", s.addr)
	for {
		conn, err := ln.Accept()
		if err != nil {
			log.Printf("accept error: %v", err)
			continue
		}
		go s.handleConn(conn)
	}
}

func (s *Server) handleConn(conn net.Conn) {
	reader := bufio.NewReader(conn)

	headers := make(map[string]string)
	for {
		line, err := reader.ReadString('\n')
		if err != nil {
			conn.Close()
			return
		}
		line = strings.TrimSpace(line)
		if line == "" {
			break
		}
		parts := strings.SplitN(line, ":", 2)
		if len(parts) != 2 {
			continue
		}
		k := strings.ToLower(strings.TrimSpace(parts[0]))
		v := strings.TrimSpace(parts[1])
		headers[k] = v
	}

	name := headers["x-name"]
	if name == "" {
		name = "guest"
	}
	roleHeader := strings.ToLower(headers["x-role"])
	role := RolePlayer
	switch roleHeader {
	case "admin":
		role = RoleAdmin
	case "mod":
		role = RoleMod
	default:
		role = RolePlayer
	}

	addr := conn.RemoteAddr().String()

	s.mu.Lock()
	if s.banned[addr] {
		s.mu.Unlock()
		fmt.Fprintln(conn, "You are banned.")
		conn.Close()
		return
	}
	s.nextID++
	id := fmt.Sprintf("c%d", s.nextID)
	client := &Client{
		conn:     conn,
		id:       id,
		name:     name,
		role:     role,
		addr:     addr,
		server:   s,
		lastSeen: time.Now(),
	}
	s.clients[id] = client
	s.mu.Unlock()

	client.sendLine(fmt.Sprintf("WELCOME %s (%s)", client.name, client.id))
	s.broadcast(fmt.Sprintf("SYSTEM %s joined as %s", client.name, client.role), client.id)

	log.Printf("client connected id=%s name=%s role=%s addr=%s", client.id, client.name, client.role, client.addr)

	scanner := bufio.NewScanner(reader)
	for scanner.Scan() {
		text := strings.TrimSpace(scanner.Text())
		if text == "" {
			continue
		}
		client.lastSeen = time.Now()
		if strings.HasPrefix(text, "/") {
			s.handleCommand(client, text)
			continue
		}
		s.broadcast(fmt.Sprintf("CHAT %s: %s", client.name, text), "")
	}

	s.removeClient(client.id)
	s.broadcast(fmt.Sprintf("SYSTEM %s left", client.name), client.id)
	client.close()
	log.Printf("client disconnected id=%s name=%s", client.id, client.name)
}

func (s *Server) handleCommand(c *Client, input string) {
	fields := strings.Fields(input)
	if len(fields) == 0 {
		return
	}

	cmd := strings.ToLower(strings.TrimPrefix(fields[0], "/"))

	switch cmd {
	case "kick":
		if !hasAtLeastRole(c.role, RoleMod) {
			c.sendLine("ERR insufficient permissions")
			return
		}
		if len(fields) < 2 {
			c.sendLine("ERR usage: /kick <nameOrID>")
			return
		}
		target := s.findClient(fields[1])
		if target == nil {
			c.sendLine("ERR target not found")
			return
		}
		target.sendLine("You were kicked.")
		target.close()
		s.removeClient(target.id)
		s.broadcast(fmt.Sprintf("SYSTEM %s kicked %s", c.name, target.name), "")
	case "ban":
		if !hasAtLeastRole(c.role, RoleAdmin) {
			c.sendLine("ERR insufficient permissions")
			return
		}
		if len(fields) < 2 {
			c.sendLine("ERR usage: /ban <nameOrID>")
			return
		}
		target := s.findClient(fields[1])
		if target == nil {
			c.sendLine("ERR target not found")
			return
		}
		s.mu.Lock()
		s.banned[target.addr] = true
		s.mu.Unlock()
		target.sendLine("You were banned.")
		target.close()
		s.removeClient(target.id)
		s.broadcast(fmt.Sprintf("SYSTEM %s banned %s", c.name, target.name), "")
	case "giveitems":
		if !hasAtLeastRole(c.role, RoleMod) {
			c.sendLine("ERR insufficient permissions")
			return
		}
		if len(fields) < 4 {
			c.sendLine("ERR usage: /giveitems <nameOrID> <item> <count>")
			return
		}
		target := s.findClient(fields[1])
		if target == nil {
			c.sendLine("ERR target not found")
			return
		}
		item := fields[2]
		count := fields[3]
		target.sendLine(fmt.Sprintf("SYSTEM you received %s x%s", item, count))
		s.broadcast(fmt.Sprintf("SYSTEM %s gave %s x%s to %s", c.name, item, count, target.name), "")
	case "who":
		s.mu.RLock()
		list := make([]string, 0, len(s.clients))
		for _, cl := range s.clients {
			list = append(list, fmt.Sprintf("%s(%s,%s)", cl.name, cl.id, cl.role))
		}
		s.mu.RUnlock()
		c.sendLine("ONLINE " + strings.Join(list, ", "))
	default:
		c.sendLine("ERR unknown command")
	}
}

func hasAtLeastRole(got Role, need Role) bool {
	order := map[Role]int{
		RolePlayer: 0,
		RoleMod:    1,
		RoleAdmin:  2,
	}
	return order[got] >= order[need]
}

func (s *Server) findClient(nameOrID string) *Client {
	s.mu.RLock()
	defer s.mu.RUnlock()
	for _, c := range s.clients {
		if c.id == nameOrID || strings.EqualFold(c.name, nameOrID) {
			return c
		}
	}
	return nil
}

func (s *Server) removeClient(id string) {
	s.mu.Lock()
	delete(s.clients, id)
	s.mu.Unlock()
}

func (s *Server) broadcast(msg string, exceptID string) {
	s.mu.RLock()
	clients := make([]*Client, 0, len(s.clients))
	for _, c := range s.clients {
		if c.id == exceptID {
			continue
		}
		clients = append(clients, c)
	}
	s.mu.RUnlock()

	for _, c := range clients {
		c.sendLine(msg)
	}
}

func (c *Client) sendLine(msg string) {
	c.sendMu.Lock()
	defer c.sendMu.Unlock()
	if c.closed {
		return
	}
	_, _ = fmt.Fprintln(c.conn, msg)
}

func (c *Client) close() {
	c.closeMu.Lock()
	defer c.closeMu.Unlock()
	if c.closed {
		return
	}
	c.closed = true
	_ = c.conn.Close()
}

